module RefModule (
    input clk,
    input rst,
    input [7:0] desired_output,
    input [7:0] current_output,
    output reg [7:0] control_signal
);
    reg [2:0] pipeline_reg;
    reg [7:0] error;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            pipeline_reg <= 3'b000;
            control_signal <= 8'b00000000;
        end else begin
            error <= desired_output - current_output;
            case (pipeline_reg)
                3'b000: begin
                    control_signal <= error; // First cycle: set control signal to error
                    pipeline_reg <= 3'b001;
                end
                3'b001: begin
                    control_signal <= error; // Second cycle: maintain control signal
                    pipeline_reg <= 3'b010;
                end
                3'b010: begin
                    control_signal <= error; // Third cycle: maintain control signal
                    pipeline_reg <= 3'b000; // Reset pipeline_reg after three cycles
                end
                default: pipeline_reg <= 3'b000;
            endcase
        end
    end
endmodule
